      font-size: var(--font-size-md);
      cursor: pointer;
      transition: var(--transition-fast);
    }
    .search-button:hover {
      background: var(--color-accent);
    }
    .recipe-list {
      display: grid;
      grid-template-columns: 1fr;
      gap: var(--space-lg);
    }
